// ─── Utilities ───────────────────────────────────────────────────────────────

const MAX_POINTS = 30;

function randBetween(min, max) {
  return Math.round((Math.random() * (max - min) + min) * 10) / 10;
}

function makeInitialSeries(min, max) {
  return Array.from({ length: MAX_POINTS }, (_, i) => ({
    t: i,
    // Occasional null creates realistic data-drop gaps (network blips, polling misses)
    v: Math.random() < 0.07 ? null : randBetween(min, max),
  }));
}

