// ─── Overview Tab ─────────────────────────────────────────────────────────────

const CustomTooltip = ({ active, payload, label, unit }) => {
  if (active && payload && payload.length) {
    return (
      <div style={{
        background: "#1e293b", border: "1px solid #334155",
        borderRadius: "6px", padding: "6px 12px", fontSize: "12px",
      }}>
        <p style={{ color: "#64748b", margin: 0 }}>t={label}</p>
        <p style={{ color: "#93c5fd", fontWeight: "bold", margin: 0 }}>
          {payload[0].value}{unit}
        </p>
      </div>
    );
  }
  return null;
};

function StatCard({ label, value, color }) {
  return (
    <div style={{
      background: "#0f172a", border: "1px solid #1e293b",
      borderRadius: "10px", padding: "16px",
    }}>
      <p style={{ margin: "0 0 4px", fontSize: "10px", color: "#475569", textTransform: "uppercase", letterSpacing: "0.1em" }}>
        {label}
      </p>
      <p style={{ margin: 0, fontSize: "22px", fontWeight: "bold", color }}>{value}</p>
    </div>
  );
}

