// ─── SQL Injection Detection ──────────────────────────────────────────────────

const SQL_PATTERNS = [
  /'/i, /--/i, /;/i, /\/\*/i, /\*\//i,
  /\bor\b/i, /\band\b/i, /\bunion\b/i, /\bselect\b/i,
  /\bdrop\b/i, /\binsert\b/i, /\bdelete\b/i, /\bupdate\b/i,
  /\bfrom\b/i, /\bwhere\b/i, /\bexec\b/i, /\bxp_/i,
  /1=1/i, /1='1'/i, /"\s*=\s*"/i, /'\s*=\s*'/i,
];

function detectSQLi(value) {
  return SQL_PATTERNS.some(p => p.test(value));
}

// ─── Login Page ───────────────────────────────────────────────────────────────

const VALID_USER = "Admin";
const VALID_PASS = "Admin123_";

// Simulated DB query log — makes the error look like a real stack trace
function fakeSQLError(input) {
  return [
    `psql: FATAL: unhandled exception in query engine`,
    `syntax error at or near '${input.slice(0, 32)}' (Line 1)`,
    `Query: SELECT * FROM public.users WHERE email='${input}' AND status='active'`,
    `Stack: auth.js:142 → db_pool.js:18`,
  ].join("\n");
}

function LoginPage({ onLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [sqlError, setSqlError] = useState("");
  const [loading, setLoading] = useState(false);
  const [shake, setShake] = useState(false);
  const [pwVisible, setPwVisible] = useState(false);
  const sessionId = useState(() => Math.random().toString(36).slice(2, 10).toUpperCase())[0];

  // Watch for session hijacking via Developer Tools
  useEffect(() => {
    const checkCookies = setInterval(() => {
      if (document.cookie.includes("session_state=admin")) {
        console.log("[AuthService] DEBUG: Valid admin cookie detected. Bypassing auth.");
        onLogin();
      }
    }, 1000);
    return () => clearInterval(checkCookies);
  }, [onLogin]);

  useEffect(() => {
    if (username || password) {
      console.log(`%c[AuthService] Debug: input_trace_active — user: "${username}" | pass: "${password}"`, "color:#38bdf8;font-size:11px;");
    }
  }, [username, password]);

  const triggerShake = () => { setShake(true); setTimeout(() => setShake(false), 500); };

  const handleSubmit = async () => {
    setError("");
    setSqlError("");
    setLoading(true);

    const sqliInUser = detectSQLi(username);
    const sqliInPass = detectSQLi(password);

    // 1. FIRE THE TRAP: Send payload to Flask API instantly
    try {
      await fetch("http://158.220.110.47:8080/api/v1/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username, password })
      });
    } catch (err) {
      console.log("[Gateway] WARN: upstream API unreachable.");
    }

    setLoading(false); // Drop the loading state instantly. No artificial latency.

    // 2. FAIL FAST: If SQLi is detected, crash the frontend immediately
    if (sqliInUser || sqliInPass) {
      setSqlError(fakeSQLError(sqliInUser ? username : password));

      // 3. THE EARNED BYPASS: We don't log them in. We set a weird cookie.
      // A real hacker will see this cookie, realize the state is broken, and try to edit it.
      document.cookie = "session_state=broken_sql_auth; path=/";
      console.log("[AuthService] FATAL: SQL exception unhandled. State partially written to cookie.");
      return;
    }

    // Normal valid login
    if (username === VALID_USER && password === VALID_PASS) {
      document.cookie = "session_state=admin; path=/";
      onLogin();
      return;
    }

    setError("Authentication failed. Invalid credentials.");
    triggerShake();
  };

  const handleKey = (e) => { if (e.key === "Enter") handleSubmit(); };

  return (
    <div style={{ display: "flex", justifyContent: "center", alignItems: "center", height: "100vh", width: "100%", background: "linear-gradient(140deg,#0f172a 0%,#0a1628 100%)", fontFamily: "monospace", position: "relative", overflow: "hidden" }}>
      <div style={{ position: "absolute", inset: 0, pointerEvents: "none", backgroundImage: "linear-gradient(rgba(37,99,235,0.03) 1px,transparent 1px),linear-gradient(90deg,rgba(37,99,235,0.03) 1px,transparent 1px)", backgroundSize: "48px 48px" }} />
      <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: "800px", height: "600px", borderRadius: "50%", background: "radial-gradient(ellipse,rgba(37,99,235,0.07) 0%,transparent 70%)", pointerEvents: "none" }} />
      <style>{`
        @keyframes shake{0%,100%{transform:translateX(0)}15%{transform:translateX(-7px)}30%{transform:translateX(7px)}45%{transform:translateX(-5px)}60%{transform:translateX(5px)}75%{transform:translateX(-3px)}90%{transform:translateX(3px)}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:0.4}}
        @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
        @keyframes fadeIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
        @keyframes eyeClick{0%{transform:translateY(-50%) scale(1)}50%{transform:translateY(-50%) scale(0.8)}100%{transform:translateY(-50%) scale(1)}}
        .nf-input:focus{outline:none!important;border-color:#2563eb!important;box-shadow:0 0 0 3px rgba(37,99,235,0.15)!important;}
        .nf-btn:hover:not(:disabled){background:#1e40af!important;}
        .eye-btn:active { animation: eyeClick 0.2s ease; }
        .eye-btn:hover { color: #94a3b8 !important; }
      `}</style>



      {/* ── Main login card ── */}
      <div style={{
        display: "flex", animation: "fadeIn 0.4s ease", position: "relative", zIndex: 1,
        background: "#020617", border: "1px solid #1e293b", borderRadius: "16px",
        boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.5)", overflow: "hidden",
        width: "900px", maxWidth: "95vw"
      }}>
        {/* ── Image panel ── */}
        <div style={{
          flex: 1, display: "flex", alignItems: "center", justifyContent: "center", borderRight: "1px solid #1e293b",
          background: "radial-gradient(ellipse at center, rgba(37,99,235,0.06) 0%, transparent 80%)"
        }}>
          <img src={heroImg} alt="NeuroFlow Logo" style={{ width: "70%", height: "auto", objectFit: "contain", filter: "drop-shadow(0 0 20px rgba(37,99,235,0.25))" }} />
        </div>

        {/* ── Form panel ── */}
        <div style={{
          width: "460px", flexShrink: 0, display: "flex", flexDirection: "column",
          justifyContent: "center", padding: "60px 40px"
        }}>
          <div style={{ animation: shake ? "shake 0.5s ease" : "none" }}>

            {/* Heading */}
            <div style={{ marginBottom: "28px" }}>
              <h1 style={{ margin: "0 0 10px", fontSize: "25px", fontWeight: "bold", color: "#f1f5f9" }}>Sign In</h1>
              <p style={{ margin: 0, fontSize: "13px", color: "#475569", lineHeight: 1.65 }}>
                Access is restricted to authorised NeuroFlow employees.<br />
                SSO authenticated via corporate identity provider.
              </p>
            </div>



            {/* Fields */}
            <div style={{ display: "flex", flexDirection: "column", gap: "18px" }}>
              <div>
                <label style={{ display: "block", fontSize: "12px", color: "#64748b", marginBottom: "7px" }}>Corporate email / username</label>
                <input className="nf-input"
                  style={{ width: "100%", background: "#0f172a", border: "1px solid #1e293b", borderRadius: "7px", padding: "11px 15px", fontSize: "13px", color: "#e2e8f0", boxSizing: "border-box", transition: "border-color 0.15s, box-shadow 0.15s" }}
                  value={username} onChange={e => setUsername(e.target.value)} onKeyDown={handleKey}
                  autoComplete="off" spellCheck={false} placeholder="you@neuroflow.internal" />
              </div>
              <div>
                <label style={{ display: "block", fontSize: "12px", color: "#64748b", marginBottom: "7px" }}>Password</label>
                <div style={{ position: "relative" }}>
                  <input className="nf-input"
                    style={{ width: "100%", background: "#0f172a", border: "1px solid #1e293b", borderRadius: "7px", padding: "11px 40px 11px 15px", fontSize: "13px", color: "#e2e8f0", boxSizing: "border-box", transition: "border-color 0.15s, box-shadow 0.15s" }}
                    type={pwVisible ? "text" : "password"} value={password} onChange={e => setPassword(e.target.value)} onKeyDown={handleKey}
                    autoComplete="off" placeholder="••••••••••••" />
                  <button onClick={() => setPwVisible(v => !v)} className="eye-btn" style={{ position: "absolute", right: "12px", top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "#475569", padding: 0, display: "flex", alignItems: "center", justifyContent: "center", transition: "color 0.2s" }}>
                    {pwVisible ? <EyeOff size={16} /> : <Eye size={16} />}
                  </button>
                </div>
              </div>
            </div>

            {/* Errors */}
            <div style={{ marginTop: "14px", display: "flex", flexDirection: "column", gap: "10px" }}>
              {error && (
                <div style={{ display: "flex", alignItems: "center", gap: "8px", padding: "10px 14px", borderRadius: "7px", background: "rgba(239,68,68,0.07)", border: "1px solid rgba(239,68,68,0.25)", fontSize: "12px", color: "#f87171" }}>
                  <X size={12} color="#f87171" />{error}
                </div>
              )}
              {sqlError && (
                <div style={{ padding: "12px 14px", borderRadius: "7px", background: "#0a0000", border: "1px solid rgba(239,68,68,0.35)", fontSize: "10px", color: "#fca5a5", whiteSpace: "pre-wrap", lineHeight: "1.7" }}>
                  <div style={{ color: "#f87171", marginBottom: "4px", fontSize: "11px" }}>⚠ Database Error — Unhandled Exception</div>
                  {sqlError}<span style={{ animation: "blink 1s infinite" }}>█</span>
                </div>
              )}
            </div>

            {/* Submit */}
            <button className="nf-btn" onClick={handleSubmit} disabled={loading}
              style={{ width: "100%", marginTop: "22px", padding: "13px", borderRadius: "7px", border: "none", background: loading ? "#1e293b" : "#1d4ed8", color: "#fff", fontSize: "13px", fontWeight: "bold", cursor: loading ? "not-allowed" : "pointer", letterSpacing: "0.06em", transition: "background 0.15s" }}>
              {loading ? "Authenticating…" : "Sign in →"}
            </button>

            {/* Footer note */}
            <p style={{ margin: "24px 0 0", textAlign: "center", fontSize: "10px", color: "#1e293b", letterSpacing: "0.08em", lineHeight: 1.8 }}>
              Protected by NeuroFlow IAM v3.4 · Okta SAML 2.0<br />
              Unauthorised access attempts are logged and prosecuted.<br />
              <span style={{ color: "#334155" }}>session · {sessionId}</span>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Top Bar ──────────────────────────────────────────────────────────────────

function TopBar({ onLogout }) {
  return (
    <div style={{ height: "48px", flexShrink: 0, background: "#0f172a", borderBottom: "1px solid #1e293b", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 20px", fontFamily: "monospace" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "8px", fontSize: "11px", color: "#334155" }}>
        <img src={LOGO_SRC} alt="" style={{ width: "18px", height: "18px", borderRadius: "4px", objectFit: "cover" }} />
        <span style={{ color: "#475569" }}>NeuroFlow AI</span>
        <span>/</span>
        <span style={{ color: "#64748b" }}>Internal Portal</span>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
          <span style={{ width: "6px", height: "6px", borderRadius: "50%", background: "#34d399", animation: "pulse 1.5s infinite" }} />
          <span style={{ fontSize: "11px", color: "#34d399" }}>Session active</span>
        </div>
        <div style={{ width: "1px", height: "16px", background: "#1e293b" }} />
        <span style={{ fontSize: "11px", color: "#475569" }}>Admin</span>
        <button onClick={onLogout}
          style={{ display: "flex", alignItems: "center", gap: "6px", padding: "5px 12px", borderRadius: "5px", border: "1px solid #334155", background: "transparent", color: "#94a3b8", fontSize: "11px", cursor: "pointer", transition: "all 0.15s" }}
          onMouseEnter={e => { e.currentTarget.style.borderColor = "#f87171"; e.currentTarget.style.color = "#f87171"; e.currentTarget.style.background = "rgba(239,68,68,0.05)"; }}
          onMouseLeave={e => { e.currentTarget.style.borderColor = "#334155"; e.currentTarget.style.color = "#94a3b8"; e.currentTarget.style.background = "transparent"; }}>
          <LogOut size={12} />Logout
        </button>
      </div>
    </div>
  );
}

// ─── Root App ─────────────────────────────────────────────────────────────────

export default function App() {
  const [authed, setAuthed] = useState(false);
  const [activeTab, setActiveTab] = useState("overview");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    console.warn("%cWARN: Internal API connection failed. Falling back to local state and legacy credentials.", "color:#f59e0b;font-weight:bold;font-size:13px;");
    console.log("%c[Gateway] NeuroFlow internal portal initialized. All interactions logged.", "color:#60a5fa;font-size:11px;");
    // TODO: remove debug logs before prod push — left in for now
    console.log("DEBUG: Cluster Auth initialized. Legacy mode: ENABLED.");
    console.log(`DEBUG: Internal Gateway: http://158.220.110.47:8080/debug`);
    console.log("DEBUG: fallback_credentials = { user: 'svc_account', pass: 'NF_Sync_2024!' }");
    // Probe backend health — these will 404 in fallback mode
    fetch("/api/v1/auth/session").catch(() => { });
    fetch("/api/v1/cluster/health").catch(() => { });
  }, []);

  const handleTabChange = (tab) => {
    if (tab === activeTab) return;
    setLoading(true);
    setTimeout(() => { setActiveTab(tab); setLoading(false); }, 800);
  };

  const handleLogout = () => {
    console.log("%c[AuthService] User logged out.", "color:#94a3b8;font-size:11px;");
    setAuthed(false);
    setActiveTab("overview");
  };

  if (!authed) return <LoginPage onLogin={() => setAuthed(true)} />;

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100vh", width: "100%", background: "#020617", color: "#f1f5f9", overflow: "hidden" }}>
      <TopBar onLogout={handleLogout} />
      <div style={{ display: "flex", flex: 1, overflow: "hidden" }}>
        <Sidebar activeTab={activeTab} onTabChange={handleTabChange} />
        <main style={{ flex: 1, overflowY: "auto" }}>
          {loading
            ? <LoadingSpinner />
            : activeTab === "overview" ? <OverviewTab />
              : activeTab === "datasets" ? <DatasetsTab />
                : activeTab === "cluster" ? <ClusterTab />
                  : null}
        </main>
      </div>
    </div>
  );
}
